import React, { useContext, useState } from "react";
import { Download } from "lucide-react";
import { ContentContext } from "../context/ContentContext";

export default function FloorPlans() {
  const { content } = useContext(ContentContext);
  const floorPlans = content?.floorPlans || {};
  const [activeTab, setActiveTab] = useState("1 BHK");

  const tabs = ["1 BHK", "2 BHK", "3 BHK"];
  const thumbnails = [
    "data:image/jpeg;base64,",
    "data:image/jpeg;base64,",
    "data:image/jpeg;base64,",
  ];

  return (
    <section className="py-20 px-6 bg-white">
      <div className="max-w-7xl mx-auto">
        <h2 className="text-4xl font-bold text-gray-800 mb-12">Floor Plans</h2>

        {/* Tabs */}
        <div className="flex gap-2 mb-12 border-b-2 border-gray-200">
          {tabs.map((tab) => (
            <button
              key={tab}
              onClick={() => setActiveTab(tab)}
              className={`px-6 py-3 font-bold text-sm transition-all ${
                activeTab === tab
                  ? "text-cyan-600 border-b-4 border-cyan-600"
                  : "text-gray-400 hover:text-gray-600"
              }`}
            >
              {tab}
            </button>
          ))}
        </div>

        {/* Content */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 items-center mb-12">
          {/* Left - Floor Plan Image */}
          <div className="bg-gray-100 rounded-2xl p-4 h-96 flex items-center justify-center overflow-hidden">
            <img
              src="data:image/jpeg;base64,"
              alt="Floor Plan"
              className="w-full h-full object-cover rounded-xl"
            />
          </div>

          {/* Right - Details Card */}
          <div>
            <div className="bg-white rounded-2xl shadow-lg p-8 space-y-6">
              <div>
                <p className="text-gray-500 text-sm font-semibold mb-2">TYPE</p>
                <p className="text-2xl font-bold text-gray-800">
                  {floorPlans.type || "1 BHK / 2 BHK / 3 BHK"}
                </p>
              </div>

              <div>
                <p className="text-gray-500 text-sm font-semibold mb-2">AREA</p>
                <p className="text-2xl font-bold text-gray-800">
                  {floorPlans.area || "500 - 1200 Sq.ft"}
                </p>
              </div>

              <div>
                <p className="text-gray-500 text-sm font-semibold mb-2">PRICE</p>
                <p className="text-3xl font-bold text-cyan-600">
                  {floorPlans.priceText || "Starting from ₹69.99 Lacs"}
                </p>
              </div>

              <button className="w-full bg-lime-500 hover:bg-lime-600 text-white rounded-full py-3 flex items-center justify-center gap-2 transition transform hover:scale-105 font-semibold shadow-lg">
                <Download className="w-5 h-5" />
                Download Floor Plan
              </button>
            </div>
          </div>
        </div>

        {/* Thumbnail Gallery */}
        <div className="grid grid-cols-3 gap-4">
          {thumbnails.map((thumb, index) => (
            <img
              key={index}
              src={thumb}
              alt={`Thumbnail ${index + 1}`}
              className="w-full h-24 rounded-xl object-cover cursor-pointer hover:opacity-80 transition shadow-md"
            />
          ))}
        </div>
      </div>
    </section>
  );
}
